import { ZyfaiSDK } from '@zyfai/sdk';

const sdk = new ZyfaiSDK({ apiKey: process.env.ZYFAI_API_KEY });
const userAddress = '0xYourEOA';

// 1. Deploy deterministic subaccount (Safe) linked to EOA
const subaccount = await sdk.deploy({ userAddress });
console.log('Subaccount:', subaccount.address);

// 2. Enable automated yield optimization via session key
await sdk.enableSession({ userAddress });

// 3. Deposit funds — subaccount starts earning immediately
await sdk.deposit({ userAddress, amount: '1000', token: 'USDC' });

// 4. Check current yield and positions
const positions = await sdk.getPositions({ userAddress });

// 5. Withdraw anytime — only EOA owner can initiate
await sdk.withdraw({ userAddress, amount: '500', token: 'USDC' });
